// src/components/Map/KakaoMap.jsx
import React, { useEffect, useRef, useState, useCallback } from 'react';
import './NaverMap.scss';

const KAKAO_APP_KEY = 'a708c14abfb19860224b19457b221a25'; // 카카오 JavaScript 앱 키 입력

const getStatusClass = (count) => {
  if (count === 0) return 'soldout';
  if (count <= 3) return 'low';
  return '';
};

const KakaoMap = ({ stores, onMarkerClick }) => {
  const mapRef = useRef(null);
  const mapInstance = useRef(null);
  const markersRef = useRef([]);
  const [mapLoaded, setMapLoaded] = useState(false);
  const [filter, setFilter] = useState('all');

  // 카카오 지도 스크립트 로드
  useEffect(() => {
    if (window.kakao && window.kakao.maps) {
      window.kakao.maps.load(() => setMapLoaded(true));
      return;
    }

    const script = document.createElement('script');
    script.src = `//dapi.kakao.com/v2/maps/sdk.js?appkey=${KAKAO_APP_KEY}&autoload=false`;
    script.async = true;
    script.onload = () => {
      window.kakao.maps.load(() => setMapLoaded(true));
    };
    script.onerror = () => console.error('카카오 지도 API 로드 실패');
    document.head.appendChild(script);

    return () => {
      if (document.head.contains(script)) {
        document.head.removeChild(script);
      }
    };
  }, []);

  // 지도 초기화
  useEffect(() => {
    if (!mapLoaded || !mapRef.current) return;

    const { kakao } = window;
    const options = {
      center: new kakao.maps.LatLng(37.5665, 126.9780), // 서울 중심
      level: 5,
    };
    mapInstance.current = new kakao.maps.Map(mapRef.current, options);
  }, [mapLoaded]);

  // 마커 생성/갱신
  const renderMarkers = useCallback(() => {
    if (!mapInstance.current || !window.kakao) return;

    const { kakao } = window;

    // 기존 마커/오버레이 제거
    markersRef.current.forEach(m => m.setMap(null));
    markersRef.current = [];

    const filtered = stores.filter(store => {
      if (filter === 'available') return store.duzzonCount > 3;
      if (filter === 'low') return store.duzzonCount > 0 && store.duzzonCount <= 3;
      if (filter === 'soldout') return store.duzzonCount === 0;
      return true;
    });

    filtered.forEach(store => {
      if (!store.lat || !store.lng) return;

      const statusClass = getStatusClass(store.duzzonCount);
      const countLabel = store.duzzonCount === 0 ? '품절' : `${store.duzzonCount}개`;

      const content = `
        <div class="duzzon-marker" data-id="${store.id}">
          <div class="duzzon-marker__bubble ${statusClass}">
            <span class="duzzon-marker__emoji">🍩</span>
            <div class="duzzon-marker__info">
              <span class="duzzon-marker__count">${countLabel}</span>
              <span class="duzzon-marker__label">두쫀쿠</span>
            </div>
          </div>
          <div class="duzzon-marker__pin"></div>
        </div>
      `;

      const position = new kakao.maps.LatLng(store.lat, store.lng);

      // 카카오는 CustomOverlay로 커스텀 마커 구현
      const overlay = new kakao.maps.CustomOverlay({
        position,
        content,
        yAnchor: 1.0,
        zIndex: 3,
      });

      overlay.setMap(mapInstance.current);

      // 클릭 이벤트는 DOM에서 처리 (overlay 렌더 후)
      setTimeout(() => {
        const el = document.querySelector(`.duzzon-marker[data-id="${store.id}"]`);
        if (el) {
          el.addEventListener('click', () => {
            onMarkerClick(store);
            mapInstance.current.panTo(position);
          });
        }
      }, 100);

      markersRef.current.push(overlay);
    });
  }, [stores, filter, onMarkerClick]);

  useEffect(() => {
    if (mapLoaded && mapInstance.current) {
      renderMarkers();
    }
  }, [renderMarkers, mapLoaded]);

  const availableCount = stores.filter(s => s.duzzonCount > 0).length;

  return (
    <div className="map-container">
      {!mapLoaded && (
        <div className="map-loading">
          <div className="map-loading__donut">🍩</div>
          <div className="map-loading__text">DuZZonMap 로딩 중</div>
          <div className="map-loading__sub">두쫀쿠 위치를 불러오고 있어요</div>
        </div>
      )}

      <div id="kakao-map" ref={mapRef} />

      <div className="map-filter">
        {[
          { key: 'all', label: '🗺 전체' },
          { key: 'available', label: '✅ 구매가능' },
          { key: 'low', label: '⚡ 마감임박' },
          { key: 'soldout', label: '❌ 품절' },
        ].map(f => (
          <button
            key={f.key}
            className={`map-filter__btn ${filter === f.key ? 'active' : ''}`}
            onClick={() => setFilter(f.key)}
          >
            {f.label}
          </button>
        ))}
      </div>

      <div className="map-stats">
        <span className="map-stats__count">{availableCount}</span>
        <span className="map-stats__label">구매가능 매장</span>
      </div>
    </div>
  );
};

export default KakaoMap;
